import{_ as a,o as l,c as n,ak as p,dY as e,dZ as t,d_ as o,d$ as r,e0 as i}from"./chunks/framework.DLt_otXO.js";const _=JSON.parse('{"title":"第八章 链路追踪 Sleuth&Zipkin","description":"","frontmatter":{},"headers":[],"relativePath":"java/springcloudAlibaba/链路追踪Sleuth和Zipkin.md","filePath":"java/springcloudAlibaba/链路追踪Sleuth和Zipkin.md","lastUpdated":1777258973000}'),c={name:"java/springcloudAlibaba/链路追踪Sleuth和Zipkin.md"};function E(d,s,g,y,u,h){return l(),n("div",null,[...s[0]||(s[0]=[p(`<h1 id="第八章-链路追踪-sleuth-zipkin" tabindex="-1">第八章 链路追踪 Sleuth&amp;Zipkin <a class="header-anchor" href="#第八章-链路追踪-sleuth-zipkin" aria-label="Permalink to “第八章 链路追踪 Sleuth&amp;Zipkin”">​</a></h1><p>微服务架构是一个分布式架构，它按业务划分服务单元，一个分布式系统往往有很多个服务单元。由于服务单元数量众多，业务的复杂性，如果出现了错误和异常，很难去定位。主要体现在，一个请求可能需要调用很多个服务，而内部服务的调用复杂性，决定了问题难以定位。所以微服务架构中，必须实现分布式链路追踪，去跟进一个请求到底有哪些服务参与，参与的顺序又是怎样的，从而达到每个请求的步骤清晰可见，出了问题，很快定位。</p><p>分布式链路追踪（Distributed Tracing），就是将一次分布式请求还原成调用链路，进行日志记录，性能监控并将一次分布式请求的调用情况集中展示。比如各个服务节点上的耗时、请求具体到达哪台机器上、每个服务节点的请求状态等等。</p><h2 id="_8-1-常见的链路追踪技术" tabindex="-1">8.1 常见的链路追踪技术 <a class="header-anchor" href="#_8-1-常见的链路追踪技术" aria-label="Permalink to “8.1 常见的链路追踪技术”">​</a></h2><ul><li><strong>cat</strong> ：由大众点评开源，基于Java开发的实时应用监控平台，包括实时应用监控，业务监控 。 集成</li></ul><p>方案是通过代码埋点的方式来实现监控，比如： 拦截器，过滤器等。 对代码的侵入性很大，集成</p><p>成本较高。风险较大。</p><ul><li><strong>zipkin</strong> ：由Twitter公司开源，开放源代码分布式的跟踪系统，用于收集服务的定时数据，以解决微</li></ul><p>服务架构中的延迟问题，包括：数据的收集、存储、查找和展现。该产品结合spring-cloud-sleuth</p><p>使用较为简单， 集成很方便， 但是功能较简单。</p><ul><li><strong>pinpoint</strong>： Pinpoint是韩国人开源的基于字节码注入的调用链分析，以及应用监控分析工具。特点</li></ul><p>是支持多种插件，UI功能强大，接入端无代码侵入。</p><ul><li><strong>skywalking</strong>：SkyWalking是本土开源的基于字节码注入的调用链分析，以及应用监控分析工具。特点是支持多</li></ul><p>种插件，UI功能较强，接入端无代码侵入。目前已加入Apache孵化器。</p><ul><li><strong>Sleuth</strong></li></ul><p>SpringCloud 提供的分布式系统中链路追踪解决方案。</p><h2 id="_8-2-集成链路追踪组件sleuth" tabindex="-1">8.2 集成链路追踪组件Sleuth <a class="header-anchor" href="#_8-2-集成链路追踪组件sleuth" aria-label="Permalink to “8.2 集成链路追踪组件Sleuth”">​</a></h2><ol><li><p>在product-server和order-server中添加sleuth依赖</p><div class="language-xml"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#E1E4E8;">&lt;</span><span style="color:#85E89D;">dependency</span><span style="color:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="color:#E1E4E8;">	&lt;</span><span style="color:#85E89D;">groupId</span><span style="color:#E1E4E8;">&gt;org.springframework.cloud&lt;/</span><span style="color:#85E89D;">groupId</span><span style="color:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="color:#E1E4E8;">	&lt;</span><span style="color:#85E89D;">artifactId</span><span style="color:#E1E4E8;">&gt;spring-cloud-starter-sleuth&lt;/</span><span style="color:#85E89D;">artifactId</span><span style="color:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="color:#E1E4E8;">&lt;/</span><span style="color:#85E89D;">dependency</span><span style="color:#E1E4E8;">&gt;</span></span></code></pre></div></li><li><p>订单微服务调用商品微服务，这个流程中通过@Slfj打印日志.重启服务并访问测试</p><p>订单服务日志结果:</p><p><strong><img src="`+e+'" alt="image-1101203506704"></strong></p><p>商品服务日志结果:</p><p><strong><img src="'+t+'" alt="image-1101203619884"></strong></p></li></ol><h2 id="_8-3-日志参数解释" tabindex="-1">8.3 日志参数解释 <a class="header-anchor" href="#_8-3-日志参数解释" aria-label="Permalink to “8.3 日志参数解释”">​</a></h2><p>日志格式: [order-server,c323c72e7009c077,fba72d9c65745e60,false]</p><p>1、第一个值，spring.application.name的值</p><p>2、第二个值，c323c72e7009c077 ，sleuth生成的一个ID，叫Trace ID，用来标识一条请求链路，一条请求链路中包含一个Trace ID，多个Span ID</p><p>3、第三个值，fba72d9c65745e60、spanID 基本的工作单元，获取元数据，如发送一个http</p><p>4、第四个值：true，是否要将该信息输出到zipkin服务中来收集和展示。</p><h2 id="_8-4-zipkin-sleuth整合" tabindex="-1">8.4 Zipkin+Sleuth整合 <a class="header-anchor" href="#_8-4-zipkin-sleuth整合" aria-label="Permalink to “8.4 Zipkin+Sleuth整合”">​</a></h2><p>zipkin是Twitter基于google的分布式监控系统Dapper（论文）的开发源实现，zipkin用于跟踪分布式服务之间的应用数据链路，分析处理延时，帮助我们改进系统的性能和定位故障。</p><p>官网:<a href="https://zipkin.io/" target="_blank" rel="noreferrer">https://zipkin.io/</a></p><ol><li><p>下载Zipkin的jar包，在官网可以下载.</p></li><li><p>通过命令行，输入下面的命令启动ZipKin Server</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#B392F0;">java</span><span style="color:#79B8FF;"> -jar</span><span style="color:#9ECBFF;"> zipkin-server-2.22.1-exec.jar</span></span></code></pre></div></li><li><p>通过浏览器访问 http://localhost:9411访问</p><p><strong><img src="'+o+`" alt="image-1102091554126"></strong></p></li><li><p>在订单微服务和商品微服务中添加zipkin依赖</p><div class="language-xml"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#E1E4E8;">&lt;</span><span style="color:#85E89D;">dependency</span><span style="color:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="color:#E1E4E8;">	&lt;</span><span style="color:#85E89D;">groupId</span><span style="color:#E1E4E8;">&gt;org.springframework.cloud&lt;/</span><span style="color:#85E89D;">groupId</span><span style="color:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="color:#E1E4E8;">	&lt;</span><span style="color:#85E89D;">artifactId</span><span style="color:#E1E4E8;">&gt;spring-cloud-starter-zipkin&lt;/</span><span style="color:#85E89D;">artifactId</span><span style="color:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="color:#E1E4E8;">    &lt;</span><span style="color:#85E89D;">version</span><span style="color:#E1E4E8;">&gt;2.2.8.RELEASE&lt;/</span><span style="color:#85E89D;">version</span><span style="color:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="color:#E1E4E8;">&lt;/</span><span style="color:#85E89D;">dependency</span><span style="color:#E1E4E8;">&gt;</span></span></code></pre></div></li><li><p>在订单微服务和商品微服务中添加如下配置:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#85E89D;">spring</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">  zipkin</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">    base-url</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">http://127.0.0.1:9411/</span><span style="color:#6A737D;"> #zipkin server的请求地址</span></span>
<span class="line"><span style="color:#85E89D;">    discoveryClientEnabled</span><span style="color:#E1E4E8;">: </span><span style="color:#79B8FF;">false</span><span style="color:#6A737D;"> #让nacos把它当成一个URL，而不要当做服务名</span></span>
<span class="line"><span style="color:#85E89D;">  sleuth</span><span style="color:#E1E4E8;">: </span></span>
<span class="line"><span style="color:#85E89D;">    sampler</span><span style="color:#E1E4E8;">: </span></span>
<span class="line"><span style="color:#85E89D;">      probability</span><span style="color:#E1E4E8;">: </span><span style="color:#79B8FF;">1.0</span><span style="color:#6A737D;"> #采样的百分比</span></span></code></pre></div></li><li><p>重启订单微服务和商品微服务,访问 <code>http://localhost:8091/save?uid=1&amp;pid=1</code></p></li><li><p>访问zipkin的UI界面，观察效果</p></li></ol><p><strong><img src="`+r+'" alt="image-1102092213549"></strong></p><p><strong><img src="'+i+'" alt="image-1102092245887"></strong></p>',30)])])}const b=a(c,[["render",E]]);export{_ as __pageData,b as default};
